import pandas as pd
import numpy as np

df = pd.read_csv('/Users/ed/Documents/School/S26/ECE157C/ECE157C_272C_HW2/project/datasets/AI_Student_Life_Pakistan_2026.csv')

impact_order = {
    'Significant Decline': 0,
    'Declined': 1,
    'Slight Decline': 2,
    'No Change': 3,
    'Improved': 4,
    'Significantly Improved': 5
}

satisfaction_order = {
    'Low': 0,
    'Medium': 1,
    'High': 2
}

df = df.copy()
df['Impact_Score'] = df['Impact_on_Grades'].map(impact_order)
df['Satisfaction_Score'] = df['Satisfaction_Level'].map(satisfaction_order)

# Find students with very similar study/use time (same rounded to 0.1 hour)
pairs = []
for usage, group in df.groupby('Daily_Usage_Hours'):
    if len(group) < 2:
        continue
    g = group.sort_values('Impact_Score')
    rows = g.to_dict('records')
    for i in range(len(rows)):
        for j in range(i + 1, len(rows)):
            diff = abs(rows[j]['Impact_Score'] - rows[i]['Impact_Score'])
            if diff >= 2:
                pairs.append({
                    'Daily_Usage_Hours': float(usage),
                    'Student_1_ID': int(rows[i]['Student_ID']),
                    'Student_1_Impact': rows[i]['Impact_on_Grades'],
                    'Student_1_Satisfaction': rows[i]['Satisfaction_Level'],
                    'Student_1_Purpose': rows[i]['Purpose'],
                    'Student_1_Education_Level': rows[i]['Education_Level'],
                    'Student_1_AI_Tool': rows[i]['AI_Tool_Used'],
                    'Student_1_City': rows[i]['City'],
                    'Student_2_ID': int(rows[j]['Student_ID']),
                    'Student_2_Impact': rows[j]['Impact_on_Grades'],
                    'Student_2_Satisfaction': rows[j]['Satisfaction_Level'],
                    'Student_2_Purpose': rows[j]['Purpose'],
                    'Student_2_Education_Level': rows[j]['Education_Level'],
                    'Student_2_AI_Tool': rows[j]['AI_Tool_Used'],
                    'Student_2_City': rows[j]['City'],
                    'Impact_Score_Difference': int(diff)
                })

pairs_df = pd.DataFrame(pairs)

if pairs_df.empty:
    result = {
        'similar_students': [],
        'explanation': 'No student pairs were found with identical Daily_Usage_Hours and significantly different Impact_on_Grades based on the chosen ordinal mapping.'
    }
else:
    # Keep the most contrasting examples
    pairs_df = pairs_df.sort_values(
        ['Impact_Score_Difference', 'Daily_Usage_Hours'],
        ascending=[False, True]
    ).head(10)

    factor_summaries = []
    for _, row in pairs_df.iterrows():
        differing_factors = []
        for factor, c1, c2 in [
            ('Purpose', 'Student_1_Purpose', 'Student_2_Purpose'),
            ('Education_Level', 'Student_1_Education_Level', 'Student_2_Education_Level'),
            ('AI_Tool_Used', 'Student_1_AI_Tool', 'Student_2_AI_Tool'),
            ('Satisfaction_Level', 'Student_1_Satisfaction', 'Student_2_Satisfaction'),
            ('City', 'Student_1_City', 'Student_2_City')
        ]:
            if row[c1] != row[c2]:
                differing_factors.append({
                    'factor': factor,
                    'student_1': row[c1],
                    'student_2': row[c2]
                })
        factor_summaries.append({
            'Daily_Usage_Hours': float(row['Daily_Usage_Hours']),
            'student_pair': [int(row['Student_1_ID']), int(row['Student_2_ID'])],
            'performance_comparison': {
                'student_1': row['Student_1_Impact'],
                'student_2': row['Student_2_Impact']
            },
            'possible_explanatory_factors': differing_factors
        })

    # Aggregate which factors differ most often among contrasting pairs
    factor_counts = {}
    for item in factor_summaries:
        for f in item['possible_explanatory_factors']:
            factor_counts[f['factor']] = factor_counts.get(f['factor'], 0) + 1

    result = {
        'similar_students': factor_summaries,
        'most_common_possible_factors': factor_counts,
        'explanation': (
            'Students were matched by identical Daily_Usage_Hours and flagged when their '
            'Impact_on_Grades differed substantially using an ordinal score. The most plausible '
            'explanations in this dataset are differences in Purpose of AI use, Satisfaction_Level, '
            'Education_Level, AI_Tool_Used, and sometimes City. In particular, students using AI '
            'for different purposes (such as learning vs. writing/coding/research) can show very '
            'different grade outcomes even with the same usage time.'
        )
    }

import pandas as pd
import numpy as np

df = pd.read_csv('/Users/ed/Documents/School/S26/ECE157C/ECE157C_272C_HW2/project/datasets/AI_Student_Life_Pakistan_2026.csv')

impact_order = {
    'Significant Decline': 1,
    'Declined': 2,
    'Slight Decline': 3,
    'No Change': 4,
    'Slight Improvement': 5,
    'Improved': 6,
    'Significant Improvement': 7
}

df = df.copy()
df['Impact_Score'] = df['Impact_on_Grades'].map(impact_order)

# Compare students with very similar study/usage time (same rounded daily usage hours to 0.1)
group_col = 'Daily_Usage_Hours'
pairs = []

for usage_value, grp in df.groupby(group_col):
    grp = grp.dropna(subset=['Impact_Score'])
    if len(grp) < 2:
        continue
    grp = grp.sort_values('Impact_Score')
    low = grp.iloc[0]
    high = grp.iloc[-1]
    diff = int(high['Impact_Score'] - low['Impact_Score'])
    if diff >= 2:  # significant difference in academic outcome
        differing_factors = {}
        compare_cols = [
            'Age', 'Gender', 'Education_Level', 'City',
            'AI_Tool_Used', 'Purpose', 'Satisfaction_Level'
        ]
        for col in compare_cols:
            if low[col] != high[col]:
                differing_factors[col] = {
                    'lower_performance_student': low[col].item() if hasattr(low[col], 'item') else low[col],
                    'higher_performance_student': high[col].item() if hasattr(high[col], 'item') else high[col]
                }
        pairs.append({
            'Daily_Usage_Hours': float(usage_value),
            'lower_performance_student': {
                'Student_ID': int(low['Student_ID']),
                'Impact_on_Grades': str(low['Impact_on_Grades'])
            },
            'higher_performance_student': {
                'Student_ID': int(high['Student_ID']),
                'Impact_on_Grades': str(high['Impact_on_Grades'])
            },
            'impact_score_gap': diff,
            'possible_explanatory_factors': differing_factors
        })

pairs = sorted(pairs, key=lambda x: (-x['impact_score_gap'], x['Daily_Usage_Hours']))

summary_factors = {}
for p in pairs:
    for k in p['possible_explanatory_factors'].keys():
        summary_factors[k] = summary_factors.get(k, 0) + 1

summary_factors = dict(sorted(summary_factors.items(), key=lambda x: (-x[1], x[0])))

result = {
    'students_with_similar_study_time_but_different_performance': pairs,
    'likely_explanatory_factors_summary': summary_factors,
    'interpretation': (
        "Students with the same Daily_Usage_Hours can still report different Impact_on_Grades. "
        "The differences are most plausibly associated with how they use AI (Purpose), which AI tool they use, "
        "their Satisfaction_Level, and contextual differences such as Education_Level, Age, Gender, or City. "
        "Because the dataset does not include direct study-time or GPA values, Daily_Usage_Hours is used as the closest proxy for similar study time, "
        "and Impact_on_Grades is used as the academic performance indicator."
    )
}

summary = None

if isinstance(stored_result, dict):
    summary = stored_result.get("likely_explanatory_factors_summary")

if not isinstance(summary, dict) or not summary:
    result = "Missing ranked explanatory factors summary needed to identify the top three factors."
else:
    top_three = sorted(summary.items(), key=lambda x: (-x[1], x[0]))[:3]
    result = [{"factor": factor, "count": int(count)} for factor, count in top_three]

import pandas as pd
import numpy as np

df = pd.read_csv('/Users/ed/Documents/School/S26/ECE157C/ECE157C_272C_HW2/project/datasets/AI_Student_Life_Pakistan_2026.csv')

impact_order = {
    'Significant Decline': 1,
    'Slight Decline': 2,
    'No Change': 3,
    'Improved': 4,
    'Significantly Improved': 5
}

df = df.copy()
df['Impact_Score'] = df['Impact_on_Grades'].map(impact_order)

pairs = []
n = len(df)

for i in range(n):
    for j in range(i + 1, n):
        usage_diff = abs(df.loc[i, 'Daily_Usage_Hours'] - df.loc[j, 'Daily_Usage_Hours'])
        impact_diff = abs(df.loc[i, 'Impact_Score'] - df.loc[j, 'Impact_Score'])
        if usage_diff <= 0.3 and impact_diff >= 2:
            row_i = df.loc[i]
            row_j = df.loc[j]
            differing_factors = {}
            for col in ['Education_Level', 'Purpose', 'AI_Tool_Used', 'Satisfaction_Level', 'Gender', 'City', 'Age']:
                if row_i[col] != row_j[col]:
                    differing_factors[col] = [row_i[col], row_j[col]]
            pairs.append({
                'Student_1_ID': int(row_i['Student_ID']),
                'Student_2_ID': int(row_j['Student_ID']),
                'Student_1_Daily_Usage_Hours': float(row_i['Daily_Usage_Hours']),
                'Student_2_Daily_Usage_Hours': float(row_j['Daily_Usage_Hours']),
                'Student_1_Impact_on_Grades': row_i['Impact_on_Grades'],
                'Student_2_Impact_on_Grades': row_j['Impact_on_Grades'],
                'Usage_Hours_Difference': float(round(usage_diff, 2)),
                'Impact_Score_Difference': int(impact_diff),
                'Potential_Explaining_Factors': differing_factors
            })

pairs = sorted(
    pairs,
    key=lambda x: (-x['Impact_Score_Difference'], x['Usage_Hours_Difference'], x['Student_1_ID'], x['Student_2_ID'])
)

summary = {
    'total_pairs_found': int(len(pairs)),
    'criteria': {
        'similar_study_time': 'Daily_Usage_Hours difference <= 0.3',
        'significantly_different_performance': 'Impact_on_Grades score difference >= 2'
    },
    'impact_score_mapping': impact_order,
    'examples': pairs[:10]
}

result = summary

import pandas as pd
import numpy as np

df = pd.read_csv('/Users/ed/Documents/School/S26/ECE157C/ECE157C_272C_HW2/project/datasets/AI_Student_Life_Pakistan_2026.csv')

impact_order = {
    'Significant Decline': 0,
    'Slight Decline': 1,
    'No Change': 2,
    'Improved': 3,
    'Significantly Improved': 4
}

df['Impact_Score'] = df['Impact_on_Grades'].map(impact_order)

# Group students by similar daily usage time (rounded to nearest 0.5 hour)
df['Usage_Bin'] = (df['Daily_Usage_Hours'] * 2).round() / 2

pairs = []
for usage_bin, group in df.groupby('Usage_Bin'):
    if group['Impact_Score'].nunique() > 1:
        low = group.loc[group['Impact_Score'].idxmin()]
        high = group.loc[group['Impact_Score'].idxmax()]
        if high['Impact_Score'] - low['Impact_Score'] >= 2:
            differing_factors = {}
            for col in ['Purpose', 'AI_Tool_Used', 'Satisfaction_Level', 'Education_Level', 'Age', 'Gender', 'City']:
                if low[col] != high[col]:
                    differing_factors[col] = {
                        'lower_performance_student': low[col].item() if hasattr(low[col], 'item') else low[col],
                        'higher_performance_student': high[col].item() if hasattr(high[col], 'item') else high[col]
                    }

            pairs.append({
                'Daily_Usage_Hours_Bin': float(usage_bin),
                'lower_performance_student': {
                    'Student_ID': int(low['Student_ID']),
                    'Impact_on_Grades': low['Impact_on_Grades'],
                    'Daily_Usage_Hours': float(low['Daily_Usage_Hours']),
                    'Purpose': low['Purpose'],
                    'AI_Tool_Used': low['AI_Tool_Used'],
                    'Satisfaction_Level': low['Satisfaction_Level'],
                    'Education_Level': low['Education_Level'],
                    'Age': int(low['Age']),
                    'Gender': low['Gender'],
                    'City': low['City']
                },
                'higher_performance_student': {
                    'Student_ID': int(high['Student_ID']),
                    'Impact_on_Grades': high['Impact_on_Grades'],
                    'Daily_Usage_Hours': float(high['Daily_Usage_Hours']),
                    'Purpose': high['Purpose'],
                    'AI_Tool_Used': high['AI_Tool_Used'],
                    'Satisfaction_Level': high['Satisfaction_Level'],
                    'Education_Level': high['Education_Level'],
                    'Age': int(high['Age']),
                    'Gender': high['Gender'],
                    'City': high['City']
                },
                'possible_explanatory_factors': differing_factors
            })

# Summarize broad patterns in factors among all contrasting pairs
factor_patterns = {}
for factor in ['Purpose', 'AI_Tool_Used', 'Satisfaction_Level', 'Education_Level', 'Age', 'Gender', 'City']:
    diffs = []
    for p in pairs:
        if factor in p['possible_explanatory_factors']:
            diffs.append(p['possible_explanatory_factors'][factor])
    if diffs:
        factor_patterns[factor] = diffs

result = {
    'similar_study_time_different_performance': pairs,
    'summary': (
        'Students with similar Daily_Usage_Hours can show very different Impact_on_Grades. '
        'The most plausible explanatory factors in this dataset are differences in Purpose, '
        'AI_Tool_Used, Satisfaction_Level, and Education_Level; demographic/context variables '
        'such as Age, Gender, and City may also contribute.'
    ),
    'factor_patterns': factor_patterns
}

