import pandas as pd

df = pd.read_csv('/Users/ed/Documents/School/S26/ECE157C/ECE157C_272C_HW2/project/datasets/AI_Student_Life_Pakistan_2026.csv')

cross_tab = pd.crosstab(df['Purpose'], df['Impact_on_Grades'])
row_percent = pd.crosstab(df['Purpose'], df['Impact_on_Grades'], normalize='index').mul(100).round(2)

result = {
    "count_by_purpose_and_grade_impact": {
        str(idx): {str(col): int(cross_tab.loc[idx, col]) for col in cross_tab.columns}
        for idx in cross_tab.index
    },
    "row_percent_by_purpose_and_grade_impact": {
        str(idx): {str(col): float(row_percent.loc[idx, col]) for col in row_percent.columns}
        for idx in row_percent.index
    },
    "summary": (
        "This shows how each AI usage purpose relates to reported grade impact by giving both raw counts "
        "and within-purpose percentages. Higher percentages in 'Improved' for a purpose suggest that students "
        "using AI mainly for that purpose more often reported better grades, while higher percentages in "
        "'No Change', 'Slight Decline', or 'Declined' suggest weaker or negative perceived grade impact."
    )
}

import pandas as pd

df = pd.read_csv('/Users/ed/Documents/School/S26/ECE157C/ECE157C_272C_HW2/project/datasets/AI_Student_Life_Pakistan_2026.csv')

avg_usage_by_city = (
    df.groupby('City', as_index=False)['Daily_Usage_Hours']
    .mean()
    .sort_values('Daily_Usage_Hours', ascending=False)
)

max_avg = avg_usage_by_city['Daily_Usage_Hours'].max()

top_cities = avg_usage_by_city[avg_usage_by_city['Daily_Usage_Hours'] == max_avg]

result = {
    "highest_average_daily_ai_usage_hours": float(max_avg),
    "cities": top_cities['City'].tolist(),
    "city_averages": [
        {
            "City": row['City'],
            "Average_Daily_Usage_Hours": float(row['Daily_Usage_Hours'])
        }
        for _, row in avg_usage_by_city.iterrows()
    ]
}

examples = stored_result.get("examples") if isinstance(stored_result, dict) else None

if not examples or not isinstance(examples, list):
    result = "The stored result does not include the matched pair examples needed to show the top 5 results."
else:
    top5 = examples[:5]
    result = {
        "matched_pairs_count": stored_result.get("matched_pairs_count"),
        "top_5_results": top5
    }

import pandas as pd
import numpy as np

df = pd.read_csv('/Users/ed/Documents/School/S26/ECE157C/ECE157C_272C_HW2/project/datasets/AI_Student_Life_Pakistan_2026.csv')

impact_order = {
    'Significant Decline': 1,
    'Declined': 2,
    'Slight Decline': 3,
    'No Change': 4,
    'Slight Improvement': 5,
    'Improved': 6,
    'Significantly Improved': 7
}

df['Impact_Score'] = df['Impact_on_Grades'].map(impact_order)

# Group students by very similar daily usage (rounded to nearest 0.5 hour)
df['Usage_Group'] = (df['Daily_Usage_Hours'] * 2).round() / 2

pairs = []
for usage, group in df.groupby('Usage_Group'):
    group = group.sort_values('Impact_Score')
    if group['Impact_Score'].nunique() > 1:
        low = group.iloc[0]
        high = group.iloc[-1]
        score_gap = int(high['Impact_Score'] - low['Impact_Score'])
        if score_gap >= 2:
            differing_factors = {}
            for col in ['Age', 'Gender', 'Education_Level', 'City', 'AI_Tool_Used', 'Purpose', 'Satisfaction_Level']:
                if low[col] != high[col]:
                    differing_factors[col] = [low[col], high[col]]
            pairs.append({
                'similar_daily_usage_hours': float(usage),
                'lower_performance_student': {
                    'Student_ID': int(low['Student_ID']),
                    'Impact_on_Grades': low['Impact_on_Grades'],
                    'Age': int(low['Age']),
                    'Gender': low['Gender'],
                    'Education_Level': low['Education_Level'],
                    'City': low['City'],
                    'AI_Tool_Used': low['AI_Tool_Used'],
                    'Purpose': low['Purpose'],
                    'Satisfaction_Level': low['Satisfaction_Level']
                },
                'higher_performance_student': {
                    'Student_ID': int(high['Student_ID']),
                    'Impact_on_Grades': high['Impact_on_Grades'],
                    'Age': int(high['Age']),
                    'Gender': high['Gender'],
                    'Education_Level': high['Education_Level'],
                    'City': high['City'],
                    'AI_Tool_Used': high['AI_Tool_Used'],
                    'Purpose': high['Purpose'],
                    'Satisfaction_Level': high['Satisfaction_Level']
                },
                'impact_score_gap': score_gap,
                'potential_explanatory_factors': differing_factors
            })

# Summarize which factors most often differ in these contrasting pairs
factor_counts = {}
for p in pairs:
    for factor in p['potential_explanatory_factors']:
        factor_counts[factor] = factor_counts.get(factor, 0) + 1

factor_counts = dict(sorted(factor_counts.items(), key=lambda x: (-x[1], x[0])))

result = {
    'contrasting_student_pairs_with_similar_study_time': pairs,
    'summary': {
        'total_pairs_found': len(pairs),
        'most_common_potential_factors': factor_counts,
        'interpretation': (
            "Students with similar Daily_Usage_Hours can still report very different Impact_on_Grades. "
            "The differences in these pairs are most plausibly associated with variations in Purpose, "
            "Satisfaction_Level, AI_Tool_Used, Education_Level, and other demographic/context fields where they differ. "
            "Because the dataset does not include direct grades or detailed study habits, these are suggestive factors rather than causal proof."
        )
    }
}

